// SettingsMenu.jsx

import React from 'react';
import './settings-menu.css'; // Assuming you have a CSS file for styling

const enterFullscreen = () => {
  const element = document.documentElement;

  if (element.requestFullscreen) {
    element.requestFullscreen();
  } else if (element.mozRequestFullScreen) {
    element.mozRequestFullScreen();
  } else if (element.webkitRequestFullscreen) {
    element.webkitRequestFullscreen();
  } else if (element.msRequestFullscreen) {
    element.msRequestFullscreen();
  }
};

const SettingsMenu = (props) => {
  const { toggleIsOn, handleInputSelect } = props;

  return (
    <div className="settings-menu" onClick={() => handleInputSelect('gamepad')}>
      {/* ... other JSX ... */}
      <button className="menu" onClick={() => setShowHist(true)} onTouchStart={enterFullscreen}>
        about
      </button>
      <button className="menu" onClick={() => handleInputSelect('begin')} onTouchStart={enterFullscreen}>
        begin
      </button>
      {/* ... other JSX ... */}
    </div>
  );
};

export default SettingsMenu;
